import { describe, expect, it } from "vitest";
import {
  extractPhonemeFingerprints,
  BAND_EDGES_HZ,
  type PhonemeCategory,
} from "../src/phoneme-fingerprint";

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff - 0.5;
  };
}

function sineWave(freq: number, n: number, sampleRate: number, amp = 1): Float32Array {
  const out = new Float32Array(n);
  for (let t = 0; t < n; t++) {
    out[t] = amp * Math.sin((2 * Math.PI * freq * t) / sampleRate);
  }
  return out;
}

describe("phoneme-fingerprint", () => {
  it("classifies all-zero audio as silence on every frame", () => {
    const audio = new Float32Array(4096); // zeros
    const result = extractPhonemeFingerprints({
      audio,
      sampleRate: 16000,
      nFft: 512,
      hopLength: 128,
    });
    expect(result.frames.length).toBeGreaterThan(0);
    for (const frame of result.frames) {
      expect(frame.category).toBe("silence" satisfies PhonemeCategory);
      expect(frame.totalEnergy).toBeLessThan(1e-3);
    }
  });

  it("classifies a pure 500 Hz sine as voiced with dominant band 1 or 2", () => {
    const sr = 16000;
    const audio = sineWave(500, 4096, sr, 1);
    const result = extractPhonemeFingerprints({
      audio,
      sampleRate: sr,
      nFft: 1024,
      hopLength: 256,
    });
    // Inspect interior frames (skip first/last edge windows where Hann tapers).
    const interior = result.frames.slice(2, result.frames.length - 2);
    expect(interior.length).toBeGreaterThan(0);
    for (const frame of interior) {
      // 500 Hz lives at the edge of bands 1 (200-500) and 2 (500-1000).
      expect([1, 2]).toContain(frame.dominantBand);
      expect(frame.category).toBe("voiced" satisfies PhonemeCategory);
    }
  });

  it("classifies a pure 5000 Hz sine as fricative with dominant band 6", () => {
    const sr = 16000;
    const audio = sineWave(5000, 4096, sr, 1);
    const result = extractPhonemeFingerprints({
      audio,
      sampleRate: sr,
      nFft: 1024,
      hopLength: 256,
    });
    const interior = result.frames.slice(2, result.frames.length - 2);
    expect(interior.length).toBeGreaterThan(0);
    for (const frame of interior) {
      expect(frame.dominantBand).toBe(6);
      expect(frame.category).toBe("fricative" satisfies PhonemeCategory);
    }
  });

  it("handles a mixed 800 Hz + 4500 Hz signal with a valid speech-like category", () => {
    const sr = 16000;
    const n = 4096;
    const a = sineWave(800, n, sr, 0.6);
    const b = sineWave(4500, n, sr, 0.6);
    const audio = new Float32Array(n);
    for (let i = 0; i < n; i++) audio[i] = a[i]! + b[i]!;
    const result = extractPhonemeFingerprints({
      audio,
      sampleRate: sr,
      nFft: 1024,
      hopLength: 256,
    });
    const interior = result.frames.slice(2, result.frames.length - 2);
    expect(interior.length).toBeGreaterThan(0);
    for (const frame of interior) {
      expect(["voiced", "fricative", "mixed"]).toContain(frame.category);
      // Energy should be substantial (well above silence).
      expect(frame.totalEnergy).toBeGreaterThan(1e-3);
    }
  });

  it("BAND_EDGES_HZ has 9 entries and is monotonically increasing", () => {
    expect(BAND_EDGES_HZ.length).toBe(9);
    for (let i = 1; i < BAND_EDGES_HZ.length; i++) {
      expect(BAND_EDGES_HZ[i]!).toBeGreaterThan(BAND_EDGES_HZ[i - 1]!);
    }
  });

  it("validates inputs and throws RangeError on bad parameters", () => {
    const sr = 16000;
    const ok = sineWave(440, 4096, sr, 0.5);

    // Bad nFft (not a power of two).
    expect(() =>
      extractPhonemeFingerprints({
        audio: ok,
        sampleRate: sr,
        nFft: 1000,
        hopLength: 250,
      }),
    ).toThrow(RangeError);

    // Bad hopLength (zero).
    expect(() =>
      extractPhonemeFingerprints({
        audio: ok,
        sampleRate: sr,
        nFft: 512,
        hopLength: 0,
      }),
    ).toThrow(RangeError);

    // Bad hopLength (greater than nFft).
    expect(() =>
      extractPhonemeFingerprints({
        audio: ok,
        sampleRate: sr,
        nFft: 512,
        hopLength: 1024,
      }),
    ).toThrow(RangeError);

    // Bad silenceThreshold (negative).
    expect(() =>
      extractPhonemeFingerprints({
        audio: ok,
        sampleRate: sr,
        nFft: 512,
        hopLength: 128,
        silenceThreshold: -1,
      }),
    ).toThrow(RangeError);

    // Audio shorter than nFft.
    const tiny = new Float32Array(128);
    expect(() =>
      extractPhonemeFingerprints({
        audio: tiny,
        sampleRate: sr,
        nFft: 512,
        hopLength: 128,
      }),
    ).toThrow(RangeError);
  });

  it("frames.length matches STFT nFrames (4096 samples, nFft=512, hop=128 → 29 frames)", () => {
    const sr = 16000;
    const rand = lcg(42);
    const audio = new Float32Array(4096);
    for (let i = 0; i < audio.length; i++) audio[i] = rand();
    const result = extractPhonemeFingerprints({
      audio,
      sampleRate: sr,
      nFft: 512,
      hopLength: 128,
    });
    // floor((4096 - 512) / 128) + 1 = floor(3584/128) + 1 = 28 + 1 = 29
    expect(result.frames.length).toBe(29);
    expect(result.nFft).toBe(512);
    expect(result.hopLength).toBe(128);
    expect(result.sampleRate).toBe(sr);
  });

  it("output is finite for every band, frame, and total", () => {
    const sr = 16000;
    const rand = lcg(7);
    const audio = new Float32Array(4096);
    for (let i = 0; i < audio.length; i++) audio[i] = rand();
    const result = extractPhonemeFingerprints({
      audio,
      sampleRate: sr,
      nFft: 512,
      hopLength: 128,
    });
    for (const frame of result.frames) {
      expect(Number.isFinite(frame.totalEnergy)).toBe(true);
      expect(frame.bands.length).toBe(8);
      for (let b = 0; b < frame.bands.length; b++) {
        expect(Number.isFinite(frame.bands[b]!)).toBe(true);
      }
      expect(Number.isInteger(frame.dominantBand)).toBe(true);
      expect(frame.dominantBand).toBeGreaterThanOrEqual(0);
      expect(frame.dominantBand).toBeLessThanOrEqual(7);
    }
  });
});
